:"session-start.sh","marks":[{"type":"link","attrs":{"href":"http://session-start.sh"}}]}]},{"type":"paragraph","content":[{"type":"text","text":"Approach:","marks":[{"type":"strong","attrs":{}}]},{"type":"text","text":" Check preconditions and provide helpful error messages"}]},{"type":"code_block","attrs":{"language":"bash","id":"a9a45afe-0f0d-4cff-a228-a1c8de4c5098"},"content":[{"type":"text","text":"#!/usr/bin/env bash

GARDEN_STATE="$HOME/.claude/garden-state.json"

# Check jq is installed
if ! command -v jq >/dev/null 2>&1; then
  jq -n --arg msg "⚠️  Garden plugin requires jq but it's not installed. Install: apt-get install jq" '{
    "hookSpecificOutput": {
      "hookEventName": "SessionStart",
      "additionalContext": $msg
    }
  }'
  exit 0
fi

[[ ! -f "$GARDEN_STATE" ]] && exit 0

# Check file is readable
if [[ ! -r "$GARDEN_STATE" ]]; then
  jq -n --arg msg "⚠️  Cannot read garden state: $GARDEN_STATE (check permissions)" '{
    "hookSpecificOutput": {
      "hookEventName": "SessionStart",
      "additionalContext": $msg
    }
  }'
  exit 0
fi

# Validate JSON structure
if ! jq -e '.trials' "$GARDEN_STATE" >/dev/null 2>&1; then
  jq -n --arg msg "⚠️  Garden state corrupted: $GARDEN_STATE (run /garden:repair)" '{
    "hookSpecificOutput": {
      "hookEventName": "SessionStart",
      "additionalContext": $msg
    }
  }'
  exit 0
fi

# Continue with normal logic..."}]},{"type":"paragraph","content":[{"type":"text","text":"Pros:","marks":[{"type":"strong","attrs":{}}]}]},{"type":"bullet_list","content":[{"type":"list_item","content":[{"type":"paragraph","content":[{"type":"text","text":"Clear error messages to user"}]}]},{"type":"list_item","content":[{"type":"paragraph","content":[{"type":"text","text":"Early detection of issues"}]}]},{"type":"list_item","content":[{"type":"paragraph","content":[{"type":"text","text":"Helpful troubleshooting guidance"}]}]}]},{"type":"paragraph","content":[{"type":"text","text":"Cons:","marks":[{"type":"strong","attrs":{}}]}]},{"type":"bullet_list","content":[{"type":"list_item","content":[{"type":"paragraph","content":[{"type":"text","text":"More code (adds ~20 lines)"}]}]},{"type":"list_item","content":[{"type":"paragraph","content":[{"type":"text","text":"Slightly slower (extra validation)"}]}]}]},{"type":"paragraph","content":[{"type":"text","text":"Effort:","marks":[{"type":"strong","attrs":{}}]},{"type":"text","text":" 1 hour"}]},{"type":"paragraph","content":[{"type":"text","text":"Risk:","marks":[{"type":"strong","attrs":{}}]},{"type":"text","text":" Low"}]}]}
